css:
.loader {
  display: inline-block;
  width: 49px;
  height: 49px;
  border-radius: 50%;
  border: 4px solid color-mix(in srgb, var(--loader-color) 18%, transparent);
  border-right-color: var(--loader-color);
  animation: spin 0.65s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }
